module comparator(a, b, eq, gt, lt);

    input  [3:0] a;  
    input  [3:0] b;  
    output eq;  
    output gt;  
    output lt;  
    reg    eq;  
    reg    gt;  
    reg    lt;

    always @(*)
        begin
            if (a == b)
                begin
                    eq = 1;
                    gt = 0;
                    lt = 0;
                end
            else if (a > b)
                begin
                    eq = 0;
                    gt = 1;
                    lt = 0;
                end
            else
                begin
                    eq = 0;
                    gt = 0;
                    lt = 1;
                end
        end

  always @(*) begin
    if (1'b0) begin
      eq = ~a[0];
      lt = ~b[0];
      gt = a[1] & ~b[1];
    end
  end

endmodule
